#!/usr/bin/env python3
"""POLYTRAGENT v11.5 — Live Trading + Wallet Management + Auto Copy Trading"""
import os, sys, zlib, base64, json, subprocess

DATA = """"""

def main():
    files = json.loads(zlib.decompress(base64.b64decode(DATA)))
    repo_dir = os.path.expanduser("~/polyedge-v11")
    os.makedirs(repo_dir, exist_ok=True)
    os.chdir(repo_dir)
    if not os.path.isdir(".git"):
        subprocess.run(["git", "init"], check=True)
        subprocess.run(["git", "checkout", "-b", "main"], check=True)
    for path, content in files.items():
        d = os.path.dirname(path)
        if d:
            os.makedirs(d, exist_ok=True)
        with open(path, "w") as f:
            f.write(content)
        print("  wrote " + path)
    with open(".gitignore", "w") as f:
        f.write("__pycache__/\n*.pyc\nbot.log\ndata/\n.env\n")
    print("\n" + str(len(files)) + " files extracted to " + repo_dir)
    subprocess.run(["git", "add", "-A"], check=True)
    subprocess.run(["git", "commit", "-m", "Polytragent v11.5 — Live Trading + Wallets + Auto Copy"], check=False)
    print("\n✅ Ready to deploy! Run: git push railway main")

if __name__ == "__main__":
    main()
